57	/* Syntax highlight types */
58	#define HL_NORMAL 0
59	#define HL_NONPRINT 1
60	#define HL_COMMENT 2   /* Single line comment. */
61	#define HL_MLCOMMENT 3 /* Multi-line comment. */
62	#define HL_KEYWORD1 4
63	#define HL_KEYWORD2 5
64	#define HL_STRING 6
65	#define HL_NUMBER 7
66	#define HL_MATCH 8      /* Search match. */
67	
68	#define HL_HIGHLIGHT_STRINGS (1<<0)
69	#define HL_HIGHLIGHT_NUMBERS (1<<1)
