80	/* This structure represents a single line of the file we are editing. */
81	typedef struct erow {
82	    int idx;            /* Row index in the file, zero-based. */
83	    int size;           /* Size of the row, excluding the null term. */
84	    int rsize;          /* Size of the rendered row. */
85	    char *chars;        /* Row content. */
86	    char *render;       /* Row content "rendered" for screen (for TABs). */
87	    unsigned char *hl;  /* Syntax highlight type for each character in render.*/
88	    int hl_oc;          /* Row had open comment at end in last syntax highlight
89	                           check. */
90	} erow;
