114	enum KEY_ACTION{
115	        KEY_NULL = 0,       /* NULL */
116	        CTRL_C = 3,         /* Ctrl-c */
117	        CTRL_D = 4,         /* Ctrl-d */
118	        CTRL_F = 6,         /* Ctrl-f */
119	        CTRL_H = 8,         /* Ctrl-h */
120	        TAB = 9,            /* Tab */
121	        CTRL_L = 12,        /* Ctrl+l */
122	        ENTER = 13,         /* Enter */
123	        CTRL_Q = 17,        /* Ctrl-q */
124	        CTRL_S = 19,        /* Ctrl-s */
125	        CTRL_U = 21,        /* Ctrl-u */
126	        ESC = 27,           /* Escape */
127	        BACKSPACE =  127,   /* Backspace */
128	        /* The following are just soft codes, not really reported by the
129	         * terminal directly. */
130	        ARROW_LEFT = 1000,
131	        ARROW_RIGHT,
132	        ARROW_UP,
133	        ARROW_DOWN,
134	        DEL_KEY,
135	        HOME_KEY,
136	        END_KEY,
137	        PAGE_UP,
138	        PAGE_DOWN
