143	/* =========================== Syntax highlights DB =========================
144	 *
145	 * In order to add a new syntax, define two arrays with a list of file name
146	 * matches and keywords. The file name matches are used in order to match
147	 * a given syntax with a given file name: if a match pattern starts with a
148	 * dot, it is matched as the last past of the filename, for example ".c".
149	 * Otherwise the pattern is just searched inside the filenme, like "Makefile").
150	 *
151	 * The list of keywords to highlight is just a list of words, however if they
152	 * a trailing '|' character is added at the end, they are highlighted in
153	 * a different color, so that you can have two different sets of keywords.
154	 *
155	 * Finally add a stanza in the HLDB global variable with two two arrays
156	 * of strings, and a set of flags in order to enable highlighting of
157	 * comments and numbers.
158	 *
159	 * The characters for single and multi line comments must be exactly two
160	 * and must be provided as well (see the C language example).
161	 *
162	 * There is no support to highlight patterns currently. */
163	
164	/* C / C++ */
165	char *C_HL_extensions[] = {".c",".h",".cpp",".hpp",".cc",NULL};
166	char *C_HL_keywords[] = {
167		/* C Keywords */
168		"auto","break","case","continue","default","do","else","enum",
169		"extern","for","goto","if","register","return","sizeof","static",
170		"struct","switch","typedef","union","volatile","while","NULL",
171	
172		/* C++ Keywords */
173		"alignas","alignof","and","and_eq","asm","bitand","bitor","class",
174		"compl","constexpr","const_cast","deltype","delete","dynamic_cast",
175		"explicit","export","false","friend","inline","mutable","namespace",
176		"new","noexcept","not","not_eq","nullptr","operator","or","or_eq",
177		"private","protected","public","reinterpret_cast","static_assert",
178		"static_cast","template","this","thread_local","throw","true","try",
179		"typeid","typename","virtual","xor","xor_eq",
180	
181		/* C types */
182	        "int|","long|","double|","float|","char|","unsigned|","signed|",
183	        "void|","short|","auto|","const|","bool|",NULL
184	};
185	
186	/* Here we define an array of syntax highlights by extensions, keywords,
187	 * comments delimiters and flags. */
188	struct editorSyntax HLDB[] = {
189	    {
190	        /* C / C++ */
191	        C_HL_extensions,
192	        C_HL_keywords,
193	        "//","/*","*/",
194	        HL_HIGHLIGHT_STRINGS | HL_HIGHLIGHT_NUMBERS
195	    }
196	};
197	
198	#define HLDB_ENTRIES (sizeof(HLDB)/sizeof(HLDB[0]))
