200	/* ======================= Low level terminal handling ====================== */
201	
202	static struct termios orig_termios; /* In order to restore at exit.*/
203	
204	void disableRawMode(int fd) {
205	    /* Don't even check the return value as it's too late. */
206	    if (E.rawmode) {
207	        tcsetattr(fd,TCSAFLUSH,&orig_termios);
208	        E.rawmode = 0;
209	    }
210	}
211	
212	/* Called at exit to avoid remaining in raw mode. */
213	void editorAtExit(void) {
214	    disableRawMode(STDIN_FILENO);
215	}
216	
217	/* Raw mode: 1960 magic shit. */
218	int enableRawMode(int fd) {
219	    struct termios raw;
220	
221	    if (E.rawmode) return 0; /* Already enabled. */
222	    if (!isatty(STDIN_FILENO)) goto fatal;
223	    atexit(editorAtExit);
224	    if (tcgetattr(fd,&orig_termios) == -1) goto fatal;
225	
226	    raw = orig_termios;  /* modify the original mode */
227	    /* input modes: no break, no CR to NL, no parity check, no strip char,
228	     * no start/stop output control. */
229	    raw.c_iflag &= ~(BRKINT | ICRNL | INPCK | ISTRIP | IXON);
230	    /* output modes - disable post processing */
231	    raw.c_oflag &= ~(OPOST);
232	    /* control modes - set 8 bit chars */
233	    raw.c_cflag |= (CS8);
234	    /* local modes - choing off, canonical off, no extended functions,
235	     * no signal chars (^Z,^C) */
236	    raw.c_lflag &= ~(ECHO | ICANON | IEXTEN | ISIG);
237	    /* control chars - set return condition: min number of bytes and timer. */
238	    raw.c_cc[VMIN] = 0; /* Return each byte, or zero for timeout. */
239	    raw.c_cc[VTIME] = 1; /* 100 ms timeout (unit is tens of second). */
240	
241	    /* put terminal in raw mode after flushing */
242	    if (tcsetattr(fd,TCSAFLUSH,&raw) < 0) goto fatal;
243	    E.rawmode = 1;
244	    return 0;
245	
246	fatal:
247	    errno = ENOTTY;
248	    return -1;
249	}
