251	/* Read a key from the terminal put in raw mode, trying to handle
252	 * escape sequences. */
253	int editorReadKey(int fd) {
254	    int nread;
255	    char c, seq[3];
256	    while ((nread = read(fd,&c,1)) == 0);
257	    if (nread == -1) exit(1);
258	
259	    while(1) {
260	        switch(c) {
261	        case ESC:    /* escape sequence */
262	            /* If this is just an ESC, we'll timeout here. */
263	            if (read(fd,seq,1) == 0) return ESC;
264	            if (read(fd,seq+1,1) == 0) return ESC;
265	
266	            /* ESC [ sequences. */
267	            if (seq[0] == '[') {
268	                if (seq[1] >= '0' && seq[1] <= '9') {
269	                    /* Extended escape, read additional byte. */
270	                    if (read(fd,seq+2,1) == 0) return ESC;
271	                    if (seq[2] == '~') {
272	                        switch(seq[1]) {
273	                        case '3': return DEL_KEY;
274	                        case '5': return PAGE_UP;
275	                        case '6': return PAGE_DOWN;
276	                        }
277	                    }
278	                } else {
279	                    switch(seq[1]) {
280	                    case 'A': return ARROW_UP;
281	                    case 'B': return ARROW_DOWN;
282	                    case 'C': return ARROW_RIGHT;
283	                    case 'D': return ARROW_LEFT;
284	                    case 'H': return HOME_KEY;
285	                    case 'F': return END_KEY;
286	                    }
287	                }
288	            }
289	
290	            /* ESC O sequences. */
291	            else if (seq[0] == 'O') {
292	                switch(seq[1]) {
293	                case 'H': return HOME_KEY;
294	                case 'F': return END_KEY;
295	                }
296	            }
297	            break;
298	        default:
299	            return c;
300	        }
301	    }
302	}
