304	/* Use the ESC [6n escape sequence to query the horizontal cursor position
305	 * and return it. On error -1 is returned, on success the position of the
306	 * cursor is stored at *rows and *cols and 0 is returned. */
307	int getCursorPosition(int ifd, int ofd, int *rows, int *cols) {
308	    char buf[32];
309	    unsigned int i = 0;
310	
311	    /* Report cursor location */
312	    if (write(ofd, "\x1b[6n", 4) != 4) return -1;
313	
314	    /* Read the response: ESC [ rows ; cols R */
315	    while (i < sizeof(buf)-1) {
316	        if (read(ifd,buf+i,1) != 1) break;
317	        if (buf[i] == 'R') break;
318	        i++;
319	    }
320	    buf[i] = '\0';
321	
322	    /* Parse it. */
323	    if (buf[0] != ESC || buf[1] != '[') return -1;
324	    if (sscanf(buf+2,"%d;%d",rows,cols) != 2) return -1;
325	    return 0;
326	}
327	
328	/* Try to get the number of columns in the current terminal. If the ioctl()
329	 * call fails the function will try to query the terminal itself.
330	 * Returns 0 on success, -1 on error. */
331	int getWindowSize(int ifd, int ofd, int *rows, int *cols) {
332	    struct winsize ws;
333	
334	    if (ioctl(1, TIOCGWINSZ, &ws) == -1 || ws.ws_col == 0) {
335	        /* ioctl() failed. Try to query the terminal itself. */
336	        int orig_row, orig_col, retval;
337	
338	        /* Get the initial position so we can restore it later. */
339	        retval = getCursorPosition(ifd,ofd,&orig_row,&orig_col);
340	        if (retval == -1) goto failed;
341	
342	        /* Go to right/bottom margin and get position. */
343	        if (write(ofd,"\x1b[999C\x1b[999B",12) != 12) goto failed;
344	        retval = getCursorPosition(ifd,ofd,rows,cols);
345	        if (retval == -1) goto failed;
346	
347	        /* Restore position. */
348	        char seq[32];
349	        snprintf(seq,32,"\x1b[%d;%dH",orig_row,orig_col);
350	        if (write(ofd,seq,strlen(seq)) == -1) {
351	            /* Can't recover... */
352	        }
353	        return 0;
354	    } else {
355	        *cols = ws.ws_col;
356	        *rows = ws.ws_row;
357	        return 0;
358	    }
359	
360	failed:
361	    return -1;
362	}
363	
364	/* ====================== Syntax highlight color scheme  ==================== */
365	
366	int is_separator(int c) {
367	    return c == '\0' || isspace(c) || strchr(",.()+-/*=~%[];",c) != NULL;
368	}
369	
370	/* Return true if the specified row last char is part of a multi line comment
371	 * that starts at this row or at one before, and does not end at the end
372	 * of the row but spawns to the next row. */
373	int editorRowHasOpenComment(erow *row) {
374	    if (row->hl && row->rsize && row->hl[row->rsize-1] == HL_MLCOMMENT &&
375	        (row->rsize < 2 || (row->render[row->rsize-2] != '*' ||
376	                            row->render[row->rsize-1] != '/'))) return 1;
377	    return 0;
378	}
379	
380	/* Set every byte of row->hl (that corresponds to every character in the line)
381	 * to the right syntax highlight type (HL_* defines). */
382	void editorUpdateSyntax(erow *row) {
383	    row->hl = realloc(row->hl,row->rsize);
384	    memset(row->hl,HL_NORMAL,row->rsize);
385	
386	    if (E.syntax == NULL) return; /* No syntax, everything is HL_NORMAL. */
387	
388	    int i, prev_sep, in_string, in_comment;
389	    char *p;
390	    char **keywords = E.syntax->keywords;
391	    char *scs = E.syntax->singleline_comment_start;
392	    char *mcs = E.syntax->multiline_comment_start;
393	    char *mce = E.syntax->multiline_comment_end;
394	
395	    /* Point to the first non-space char. */
396	    p = row->render;
397	    i = 0; /* Current char offset */
398	    while(*p && isspace(*p)) {
399	        p++;
400	        i++;
401	    }
402	    prev_sep = 1; /* Tell the parser if 'i' points to start of word. */
403	    in_string = 0; /* Are we inside "" or '' ? */
404	    in_comment = 0; /* Are we inside multi-line comment? */
405	
406	    /* If the previous line has an open comment, this line starts
407	     * with an open comment state. */
408	    if (row->idx > 0 && editorRowHasOpenComment(&E.row[row->idx-1]))
409	        in_comment = 1;
410	
411	    while(*p) {
412	        /* Handle // comments. */
413	        if (prev_sep && *p == scs[0] && *(p+1) == scs[1]) {
414	            /* From here to end is a comment */
415	            memset(row->hl+i,HL_COMMENT,row->size-i);
416	            return;
417	        }
418	
419	        /* Handle multi line comments. */
420	        if (in_comment) {
421	            row->hl[i] = HL_MLCOMMENT;
422	            if (*p == mce[0] && *(p+1) == mce[1]) {
423	                row->hl[i+1] = HL_MLCOMMENT;
424	                p += 2; i += 2;
425	                in_comment = 0;
426	                prev_sep = 1;
427	                continue;
428	            } else {
429	                prev_sep = 0;
430	                p++; i++;
431	                continue;
432	            }
433	        } else if (*p == mcs[0] && *(p+1) == mcs[1]) {
434	            row->hl[i] = HL_MLCOMMENT;
435	            row->hl[i+1] = HL_MLCOMMENT;
436	            p += 2; i += 2;
437	            in_comment = 1;
438	            prev_sep = 0;
439	            continue;
440	        }
441	
442	        /* Handle "" and '' */
443	        if (in_string) {
444	            row->hl[i] = HL_STRING;
445	            if (*p == '\\') {
446	                row->hl[i+1] = HL_STRING;
447	                p += 2; i += 2;
448	                prev_sep = 0;
449	                continue;
450	            }
451	            if (*p == in_string) in_string = 0;
452	            p++; i++;
453	            continue;
454	        } else {
455	            if (*p == '"' || *p == '\'') {
456	                in_string = *p;
457	                row->hl[i] = HL_STRING;
458	                p++; i++;
459	                prev_sep = 0;
460	                continue;
461	            }
462	        }
463	
464	        /* Handle non printable chars. */
465	        if (!isprint(*p)) {
466	            row->hl[i] = HL_NONPRINT;
467	            p++; i++;
468	            prev_sep = 0;
469	            continue;
470	        }
471	
472	        /* Handle numbers */
473	        if ((isdigit(*p) && (prev_sep || row->hl[i-1] == HL_NUMBER)) ||
474	            (*p == '.' && i >0 && row->hl[i-1] == HL_NUMBER)) {
475	            row->hl[i] = HL_NUMBER;
476	            p++; i++;
477	            prev_sep = 0;
478	            continue;
479	        }
480	
481	        /* Handle keywords and lib calls */
482	        if (prev_sep) {
483	            int j;
484	            for (j = 0; keywords[j]; j++) {
485	                int klen = strlen(keywords[j]);
486	                int kw2 = keywords[j][klen-1] == '|';
487	                if (kw2) klen--;
488	
489	                if (!memcmp(p,keywords[j],klen) &&
490	                    is_separator(*(p+klen)))
491	                {
492	                    /* Keyword */
493	                    memset(row->hl+i,kw2 ? HL_KEYWORD2 : HL_KEYWORD1,klen);
494	                    p += klen;
495	                    i += klen;
496	                    break;
497	                }
498	            }
499	            if (keywords[j] != NULL) {
500	                prev_sep = 0;
501	                continue; /* We had a keyword match */
502	            }
503	        }
504	
505	        /* Not special chars */
506	        prev_sep = is_separator(*p);
507	        p++; i++;
508	    }
509	
510	    /* Propagate syntax change to the next row if the open commen
511	     * state changed. This may recursively affect all the following rows
512	     * in the file. */
513	    int oc = editorRowHasOpenComment(row);
514	    if (row->hl_oc != oc && row->idx+1 < E.numrows)
515	        editorUpdateSyntax(&E.row[row->idx+1]);
516	    row->hl_oc = oc;
517	}
518	
519	/* Maps syntax highlight token types to terminal colors. */
520	int editorSyntaxToColor(int hl) {
521	    switch(hl) {
522	    case HL_COMMENT:
523	    case HL_MLCOMMENT: return 36;     /* cyan */
524	    case HL_KEYWORD1: return 33;    /* yellow */
525	    case HL_KEYWORD2: return 32;    /* green */
526	    case HL_STRING: return 35;      /* magenta */
527	    case HL_NUMBER: return 31;      /* red */
528	    case HL_MATCH: return 34;      /* blu */
529	    default: return 37;             /* white */
530	    }
531	}
532	
533	/* Select the syntax highlight scheme depending on the filename,
534	 * setting it in the global state E.syntax. */
535	void editorSelectSyntaxHighlight(char *filename) {
536	    for (unsigned int j = 0; j < HLDB_ENTRIES; j++) {
537	        struct editorSyntax *s = HLDB+j;
538	        unsigned int i = 0;
539	        while(s->filematch[i]) {
540	            char *p;
541	            int patlen = strlen(s->filematch[i]);
542	            if ((p = strstr(filename,s->filematch[i])) != NULL) {
543	                if (s->filematch[i][0] != '.' || p[patlen] == '\0') {
544	                    E.syntax = s;
545	                    return;
546	                }
547	            }
548	            i++;
549	        }
550	    }
551	}
552	
553	/* ======================= Editor rows implementation ======================= */
554	
555	/* Update the rendered version and the syntax highlight of a row. */
556	void editorUpdateRow(erow *row) {
557	    unsigned int tabs = 0, nonprint = 0;
558	    int j, idx;
559	
560	   /* Create a version of the row we can directly print on the screen,
561	     * respecting tabs, substituting non printable characters with '?'. */
562	    free(row->render);
563	    for (j = 0; j < row->size; j++)
564	        if (row->chars[j] == TAB) tabs++;
565	
566	    unsigned long long allocsize =
567	        (unsigned long long) row->size + tabs*8 + nonprint*9 + 1;
568	    if (allocsize > UINT32_MAX) {
569	        printf("Some line of the edited file is too long for kilo\n");
570	        exit(1);
571	    }
572	
573	    row->render = malloc(row->size + tabs*8 + nonprint*9 + 1);
574	    idx = 0;
575	    for (j = 0; j < row->size; j++) {
576	        if (row->chars[j] == TAB) {
577	            row->render[idx++] = ' ';
578	            while((idx+1) % 8 != 0) row->render[idx++] = ' ';
579	        } else {
580	            row->render[idx++] = row->chars[j];
581	        }
582	    }
583	    row->rsize = idx;
584	    row->render[idx] = '\0';
585	
586	    /* Update the syntax highlighting attributes of the row. */
587	    editorUpdateSyntax(row);
588	}
589	
590	/* Insert a row at the specified position, shifting the other rows on the bottom
591	 * if required. */
592	void editorInsertRow(int at, char *s, size_t len) {
593	    if (at > E.numrows) return;
594	    E.row = realloc(E.row,sizeof(erow)*(E.numrows+1));
595	    if (at != E.numrows) {
596	        memmove(E.row+at+1,E.row+at,sizeof(E.row[0])*(E.numrows-at));
597	        for (int j = at+1; j <= E.numrows; j++) E.row[j].idx++;
598	    }
599	    E.row[at].size = len;
600	    E.row[at].chars = malloc(len+1);
601	    memcpy(E.row[at].chars,s,len+1);
602	    E.row[at].hl = NULL;
603	    E.row[at].hl_oc = 0;
604	    E.row[at].render = NULL;
605	    E.row[at].rsize = 0;
606	    E.row[at].idx = at;
607	    editorUpdateRow(E.row+at);
608	    E.numrows++;
609	    E.dirty++;
610	}
