619	/* Remove the row at the specified position, shifting the remainign on the
620	 * top. */
621	void editorDelRow(int at) {
622	    erow *row;
623	
624	    if (at >= E.numrows) return;
625	    row = E.row+at;
626	    editorFreeRow(row);
627	    memmove(E.row+at,E.row+at+1,sizeof(E.row[0])*(E.numrows-at-1));
628	    for (int j = at; j < E.numrows-1; j++) E.row[j].idx++;
629	    E.numrows--;
630	    E.dirty++;
631	}
632	
633	/* Turn the editor rows into a single heap-allocated string.
634	 * Returns the pointer to the heap-allocated string and populate the
635	 * integer pointed by 'buflen' with the size of the string, escluding
636	 * the final nulterm. */
637	char *editorRowsToString(int *buflen) {
638	    char *buf = NULL, *p;
639	    int totlen = 0;
640	    int j;
641	
642	    /* Compute count of bytes */
643	    for (j = 0; j < E.numrows; j++)
644	        totlen += E.row[j].size+1; /* +1 is for "\n" at end of every row */
645	    *buflen = totlen;
646	    totlen++; /* Also make space for nulterm */
647	
648	    p = buf = malloc(totlen);
649	    for (j = 0; j < E.numrows; j++) {
650	        memcpy(p,E.row[j].chars,E.row[j].size);
651	        p += E.row[j].size;
652	        *p = '\n';
653	        p++;
654	    }
655	    *p = '\0';
656	    return buf;
657	}
658	
659	/* Insert a character at the specified position in a row, moving the remaining
660	 * chars on the right if needed. */
661	void editorRowInsertChar(erow *row, int at, int c) {
662	    if (at > row->size) {
663	        /* Pad the string with spaces if the insert location is outside the
664	         * current length by more than a single character. */
665	        int padlen = at-row->size;
666	        /* In the next line +2 means: new char and null term. */
667	        row->chars = realloc(row->chars,row->size+padlen+2);
668	        memset(row->chars+row->size,' ',padlen);
669	        row->chars[row->size+padlen+1] = '\0';
670	        row->size += padlen+1;
671	    } else {
672	        /* If we are in the middle of the string just make space for 1 new
673	         * char plus the (already existing) null term. */
674	        row->chars = realloc(row->chars,row->size+2);
675	        memmove(row->chars+at+1,row->chars+at,row->size-at+1);
676	        row->size++;
677	    }
678	    row->chars[at] = c;
679	    editorUpdateRow(row);
680	    E.dirty++;
681	}
682	
683	/* Append the string 's' at the end of a row */
684	void editorRowAppendString(erow *row, char *s, size_t len) {
685	    row->chars = realloc(row->chars,row->size+len+1);
686	    memcpy(row->chars+row->size,s,len);
687	    row->size += len;
688	    row->chars[row->size] = '\0';
689	    editorUpdateRow(row);
690	    E.dirty++;
691	}
692	
693	/* Delete the character at offset 'at' from the specified row. */
694	void editorRowDelChar(erow *row, int at) {
695	    if (row->size <= at) return;
696	    memmove(row->chars+at,row->chars+at+1,row->size-at);
697	    editorUpdateRow(row);
698	    row->size--;
699	    E.dirty++;
700	}
