702	/* Insert the specified char at the current prompt position. */
703	void editorInsertChar(int c) {
704	    int filerow = E.rowoff+E.cy;
705	    int filecol = E.coloff+E.cx;
706	    erow *row = (filerow >= E.numrows) ? NULL : &E.row[filerow];
707	
708	    /* If the row where the cursor is currently located does not exist in our
709	     * logical representaion of the file, add enough empty rows as needed. */
710	    if (!row) {
711	        while(E.numrows <= filerow)
712	            editorInsertRow(E.numrows,"",0);
713	    }
714	    row = &E.row[filerow];
715	    editorRowInsertChar(row,filecol,c);
716	    if (E.cx == E.screencols-1)
717	        E.coloff++;
718	    else
719	        E.cx++;
720	    E.dirty++;
721	}
722	
723	/* Inserting a newline is slightly complex as we have to handle inserting a
724	 * newline in the middle of a line, splitting the line as needed. */
725	void editorInsertNewline(void) {
726	    int filerow = E.rowoff+E.cy;
727	    int filecol = E.coloff+E.cx;
728	    erow *row = (filerow >= E.numrows) ? NULL : &E.row[filerow];
729	
730	    if (!row) {
731	        if (filerow == E.numrows) {
732	            editorInsertRow(filerow,"",0);
733	            goto fixcursor;
734	        }
735	        return;
736	    }
737	    /* If the cursor is over the current line size, we want to conceptually
738	     * think it's just over the last character. */
739	    if (filecol >= row->size) filecol = row->size;
740	    if (filecol == 0) {
741	        editorInsertRow(filerow,"",0);
742	    } else {
743	        /* We are in the middle of a line. Split it between two rows. */
744	        editorInsertRow(filerow+1,row->chars+filecol,row->size-filecol);
745	        row = &E.row[filerow];
746	        row->chars[filecol] = '\0';
747	        row->size = filecol;
748	        editorUpdateRow(row);
749	    }
750	fixcursor:
751	    if (E.cy == E.screenrows-1) {
752	        E.rowoff++;
753	    } else {
754	        E.cy++;
755	    }
756	    E.cx = 0;
757	    E.coloff = 0;
758	}
759	
760	/* Delete the char at the current prompt position. */
761	void editorDelChar(void) {
762	    int filerow = E.rowoff+E.cy;
763	    int filecol = E.coloff+E.cx;
764	    erow *row = (filerow >= E.numrows) ? NULL : &E.row[filerow];
765	
766	    if (!row || (filecol == 0 && filerow == 0)) return;
767	    if (filecol == 0) {
768	        /* Handle the case of column 0, we need to move the current line
769	         * on the right of the previous one. */
770	        filecol = E.row[filerow-1].size;
771	        editorRowAppendString(&E.row[filerow-1],row->chars,row->size);
772	        editorDelRow(filerow);
773	        row = NULL;
774	        if (E.cy == 0)
775	            E.rowoff--;
776	        else
777	            E.cy--;
778	        E.cx = filecol;
779	        if (E.cx >= E.screencols) {
780	            int shift = (E.screencols-E.cx)+1;
781	            E.cx -= shift;
782	            E.coloff += shift;
783	        }
784	    } else {
785	        editorRowDelChar(row,filecol-1);
786	        if (E.cx == 0 && E.coloff)
787	            E.coloff--;
788	        else
789	            E.cx--;
790	    }
791	    if (row) editorUpdateRow(row);
792	    E.dirty++;
793	}
