795	/* Load the specified program in the editor memory and returns 0 on success
796	 * or 1 on error. */
797	int editorOpen(char *filename) {
798	    FILE *fp;
799	
800	    E.dirty = 0;
801	    free(E.filename);
802	    size_t fnlen = strlen(filename)+1;
803	    E.filename = malloc(fnlen);
804	    memcpy(E.filename,filename,fnlen);
805	
806	    fp = fopen(filename,"r");
807	    if (!fp) {
808	        if (errno != ENOENT) {
809	            perror("Opening file");
810	            exit(1);
811	        }
812	        return 1;
813	    }
814	
815	    char *line = NULL;
816	    size_t linecap = 0;
817	    ssize_t linelen;
818	    while((linelen = getline(&line,&linecap,fp)) != -1) {
819	        if (linelen && (line[linelen-1] == '\n' || line[linelen-1] == '\r'))
820	            line[--linelen] = '\0';
821	        editorInsertRow(E.numrows,line,linelen);
822	    }
823	    free(line);
824	    fclose(fp);
825	    E.dirty = 0;
826	    return 0;
827	}
