829	/* Save the current file on disk. Return 0 on success, 1 on error. */
830	int editorSave(void) {
831	    int len;
832	    char *buf = editorRowsToString(&len);
833	    int fd = open(E.filename,O_RDWR|O_CREAT,0644);
834	    if (fd == -1) goto writeerr;
835	
836	    /* Use truncate + a single write(2) call in order to make saving
837	     * a bit safer, under the limits of what we can do in a small editor. */
838	    if (ftruncate(fd,len) == -1) goto writeerr;
839	    if (write(fd,buf,len) != len) goto writeerr;
840	
841	    close(fd);
842	    free(buf);
843	    E.dirty = 0;
844	    editorSetStatusMessage("%d bytes written on disk", len);
845	    return 0;
846	
847	writeerr:
848	    free(buf);
849	    if (fd != -1) close(fd);
850	    editorSetStatusMessage("Can't save! I/O error: %s",strerror(errno));
851	    return 1;
852	}
