854	/* ============================= Terminal update ============================ */
855	
856	/* We define a very simple "append buffer" structure, that is an heap
857	 * allocated string where we can append to. This is useful in order to
858	 * write all the escape sequences in a buffer and flush them to the standard
859	 * output in a single call, to avoid flickering effects. */
860	struct abuf {
861	    char *b;
862	    int len;
863	};
864	
865	#define ABUF_INIT {NULL,0}
866	
867	void abAppend(struct abuf *ab, const char *s, int len) {
868	    char *new = realloc(ab->b,ab->len+len);
869	
870	    if (new == NULL) return;
871	    memcpy(new+ab->len,s,len);
872	    ab->b = new;
873	    ab->len += len;
874	}
875	
876	void abFree(struct abuf *ab) {
877	    free(ab->b);
878	}
