880	/* This function writes the whole screen using VT100 escape characters
881	 * starting from the logical state of the editor in the global state 'E'. */
882	void editorRefreshScreen(void) {
883	    int y;
884	    erow *r;
885	    char buf[32];
886	    struct abuf ab = ABUF_INIT;
887	
888	    abAppend(&ab,"\x1b[?25l",6); /* Hide cursor. */
889	    abAppend(&ab,"\x1b[H",3); /* Go home. */
890	    for (y = 0; y < E.screenrows; y++) {
891	        int filerow = E.rowoff+y;
892	
893	        if (filerow >= E.numrows) {
894	            if (E.numrows == 0 && y == E.screenrows/3) {
895	                char welcome[80];
896	                int welcomelen = snprintf(welcome,sizeof(welcome),
897	                    "Kilo editor -- verison %s\x1b[0K\r\n", KILO_VERSION);
898	                int padding = (E.screencols-welcomelen)/2;
899	                if (padding) {
900	                    abAppend(&ab,"~",1);
901	                    padding--;
902	                }
903	                while(padding--) abAppend(&ab," ",1);
904	                abAppend(&ab,welcome,welcomelen);
905	            } else {
906	                abAppend(&ab,"~\x1b[0K\r\n",7);
907	            }
908	            continue;
909	        }
910	
911	        r = &E.row[filerow];
912	
913	        int len = r->rsize - E.coloff;
914	        int current_color = -1;
915	        if (len > 0) {
916	            if (len > E.screencols) len = E.screencols;
917	            char *c = r->render+E.coloff;
918	            unsigned char *hl = r->hl+E.coloff;
919	            int j;
920	            for (j = 0; j < len; j++) {
921	                if (hl[j] == HL_NONPRINT) {
922	                    char sym;
923	                    abAppend(&ab,"\x1b[7m",4);
924	                    if (c[j] <= 26)
925	                        sym = '@'+c[j];
926	                    else
927	                        sym = '?';
928	                    abAppend(&ab,&sym,1);
929	                    abAppend(&ab,"\x1b[0m",4);
930	                } else if (hl[j] == HL_NORMAL) {
931	                    if (current_color != -1) {
932	                        abAppend(&ab,"\x1b[39m",5);
933	                        current_color = -1;
934	                    }
935	                    abAppend(&ab,c+j,1);
936	                } else {
937	                    int color = editorSyntaxToColor(hl[j]);
938	                    if (color != current_color) {
939	                        char buf[16];
940	                        int clen = snprintf(buf,sizeof(buf),"\x1b[%dm",color);
941	                        current_color = color;
942	                        abAppend(&ab,buf,clen);
943	                    }
944	                    abAppend(&ab,c+j,1);
945	                }
946	            }
947	        }
948	        abAppend(&ab,"\x1b[39m",5);
949	        abAppend(&ab,"\x1b[0K",4);
950	        abAppend(&ab,"\r\n",2);
951	    }
952	
953	    /* Create a two rows status. First row: */
954	    abAppend(&ab,"\x1b[0K",4);
955	    abAppend(&ab,"\x1b[7m",4);
956	    char status[80], rstatus[80];
957	    int len = snprintf(status, sizeof(status), "%.20s - %d lines %s",
958	        E.filename, E.numrows, E.dirty ? "(modified)" : "");
959	    int rlen = snprintf(rstatus, sizeof(rstatus),
960	        "%d/%d",E.rowoff+E.cy+1,E.numrows);
961	    if (len > E.screencols) len = E.screencols;
962	    abAppend(&ab,status,len);
963	    while(len < E.screencols) {
964	        if (E.screencols - len == rlen) {
965	            abAppend(&ab,rstatus,rlen);
966	            break;
967	        } else {
968	            abAppend(&ab," ",1);
969	            len++;
970	        }
971	    }
972	    abAppend(&ab,"\x1b[0m\r\n",6);
973	
974	    /* Second row depends on E.statusmsg and the status message update time. */
975	    abAppend(&ab,"\x1b[0K",4);
976	    int msglen = strlen(E.statusmsg);
977	    if (msglen && time(NULL)-E.statusmsg_time < 5)
978	        abAppend(&ab,E.statusmsg,msglen <= E.screencols ? msglen : E.screencols);
979	
980	    /* Put cursor at its current position. Note that the horizontal position
981	     * at which the cursor is displayed may be different compared to 'E.cx'
982	     * because of TABs. */
983	    int j;
984	    int cx = 1;
985	    int filerow = E.rowoff+E.cy;
986	    erow *row = (filerow >= E.numrows) ? NULL : &E.row[filerow];
987	    if (row) {
988	        for (j = E.coloff; j < (E.cx+E.coloff); j++) {
989	            if (j < row->size && row->chars[j] == TAB) cx += 7-((cx)%8);
990	            cx++;
991	        }
992	    }
993	    snprintf(buf,sizeof(buf),"\x1b[%d;%dH",E.cy+1,cx);
994	    abAppend(&ab,buf,strlen(buf));
995	    abAppend(&ab,"\x1b[?25h",6); /* Show cursor. */
996	    write(STDOUT_FILENO,ab.b,ab.len);
997	    abFree(&ab);
998	}
