1010	/* =============================== Find mode ================================ */
1011	
1012	#define KILO_QUERY_LEN 256
1013	
1014	void editorFind(int fd) {
1015	    char query[KILO_QUERY_LEN+1] = {0};
1016	    int qlen = 0;
1017	    int last_match = -1; /* Last line where a match was found. -1 for none. */
1018	    int find_next = 0; /* if 1 search next, if -1 search prev. */
1019	    int saved_hl_line = -1;  /* No saved HL */
1020	    char *saved_hl = NULL;
1021	
1022	#define FIND_RESTORE_HL do { \
1023	    if (saved_hl) { \
1024	        memcpy(E.row[saved_hl_line].hl,saved_hl, E.row[saved_hl_line].rsize); \
1025	        free(saved_hl); \
1026	        saved_hl = NULL; \
1027	    } \
1028	} while (0)
1029	
1030	    /* Save the cursor position in order to restore it later. */
1031	    int saved_cx = E.cx, saved_cy = E.cy;
1032	    int saved_coloff = E.coloff, saved_rowoff = E.rowoff;
1033	
1034	    while(1) {
1035	        editorSetStatusMessage(
1036	            "Search: %s (Use ESC/Arrows/Enter)", query);
1037	        editorRefreshScreen();
1038	
1039	        int c = editorReadKey(fd);
1040	        if (c == DEL_KEY || c == CTRL_H || c == BACKSPACE) {
1041	            if (qlen != 0) query[--qlen] = '\0';
1042	            last_match = -1;
1043	        } else if (c == ESC || c == ENTER) {
1044	            if (c == ESC) {
1045	                E.cx = saved_cx; E.cy = saved_cy;
1046	                E.coloff = saved_coloff; E.rowoff = saved_rowoff;
1047	            }
1048	            FIND_RESTORE_HL;
1049	            editorSetStatusMessage("");
1050	            return;
1051	        } else if (c == ARROW_RIGHT || c == ARROW_DOWN) {
1052	            find_next = 1;
1053	        } else if (c == ARROW_LEFT || c == ARROW_UP) {
1054	            find_next = -1;
1055	        } else if (isprint(c)) {
1056	            if (qlen < KILO_QUERY_LEN) {
1057	                query[qlen++] = c;
1058	                query[qlen] = '\0';
1059	                last_match = -1;
1060	            }
1061	        }
1062	
1063	        /* Search occurrence. */
1064	        if (last_match == -1) find_next = 1;
1065	        if (find_next) {
1066	            char *match = NULL;
1067	            int match_offset = 0;
1068	            int i, current = last_match;
1069	
1070	            for (i = 0; i < E.numrows; i++) {
1071	                current += find_next;
1072	                if (current == -1) current = E.numrows-1;
1073	                else if (current == E.numrows) current = 0;
1074	                match = strstr(E.row[current].render,query);
1075	                if (match) {
1076	                    match_offset = match-E.row[current].render;
1077	                    break;
1078	                }
1079	            }
1080	            find_next = 0;
1081	
1082	            /* Highlight */
1083	            FIND_RESTORE_HL;
1084	
1085	            if (match) {
1086	                erow *row = &E.row[current];
1087	                last_match = current;
1088	                if (row->hl) {
1089	                    saved_hl_line = current;
1090	                    saved_hl = malloc(row->rsize);
1091	                    memcpy(saved_hl,row->hl,row->rsize);
1092	                    memset(row->hl+match_offset,HL_MATCH,qlen);
1093	                }
1094	                E.cy = 0;
1095	                E.cx = match_offset;
1096	                E.rowoff = current;
1097	                E.coloff = 0;
1098	                /* Scroll horizontally as needed. */
1099	                if (E.cx > E.screencols) {
1100	                    int diff = E.cx - E.screencols;
1101	                    E.cx -= diff;
1102	                    E.coloff += diff;
1103	                }
1104	            }
1105	        }
1106	    }
1107	}
