1111	/* Handle cursor position change because arrow keys were pressed. */
1112	void editorMoveCursor(int key) {
1113	    int filerow = E.rowoff+E.cy;
1114	    int filecol = E.coloff+E.cx;
1115	    int rowlen;
1116	    erow *row = (filerow >= E.numrows) ? NULL : &E.row[filerow];
1117	
1118	    switch(key) {
1119	    case ARROW_LEFT:
1120	        if (E.cx == 0) {
1121	            if (E.coloff) {
1122	                E.coloff--;
1123	            } else {
1124	                if (filerow > 0) {
1125	                    E.cy--;
1126	                    E.cx = E.row[filerow-1].size;
1127	                    if (E.cx > E.screencols-1) {
1128	                        E.coloff = E.cx-E.screencols+1;
1129	                        E.cx = E.screencols-1;
1130	                    }
1131	                }
1132	            }
1133	        } else {
1134	            E.cx -= 1;
1135	        }
1136	        break;
1137	    case ARROW_RIGHT:
1138	        if (row && filecol < row->size) {
1139	            if (E.cx == E.screencols-1) {
1140	                E.coloff++;
1141	            } else {
1142	                E.cx += 1;
1143	            }
1144	        } else if (row && filecol == row->size) {
1145	            E.cx = 0;
1146	            E.coloff = 0;
1147	            if (E.cy == E.screenrows-1) {
1148	                E.rowoff++;
1149	            } else {
1150	                E.cy += 1;
1151	            }
1152	        }
1153	        break;
1154	    case ARROW_UP:
1155	        if (E.cy == 0) {
1156	            if (E.rowoff) E.rowoff--;
1157	        } else {
1158	            E.cy -= 1;
1159	        }
1160	        break;
1161	    case ARROW_DOWN:
1162	        if (filerow < E.numrows) {
1163	            if (E.cy == E.screenrows-1) {
1164	                E.rowoff++;
1165	            } else {
1166	                E.cy += 1;
1167	            }
1168	        }
1169	        break;
1170	    }
1171	    /* Fix cx if the current line has not enough chars. */
1172	    filerow = E.rowoff+E.cy;
1173	    filecol = E.coloff+E.cx;
1174	    row = (filerow >= E.numrows) ? NULL : &E.row[filerow];
1175	    rowlen = row ? row->size : 0;
1176	    if (filecol > rowlen) {
1177	        E.cx -= filecol-rowlen;
1178	        if (E.cx < 0) {
1179	            E.coloff += E.cx;
1180	            E.cx = 0;
1181	        }
1182	    }
1183	}
