1185	/* Process events arriving from the standard input, which is, the user
1186	 * is typing stuff on the terminal. */
1187	#define KILO_QUIT_TIMES 3
1188	void editorProcessKeypress(int fd) {
1189	    /* When the file is modified, requires Ctrl-q to be pressed N times
1190	     * before actually quitting. */
1191	    static int quit_times = KILO_QUIT_TIMES;
1192	
1193	    int c = editorReadKey(fd);
1194	    switch(c) {
1195	    case ENTER:         /* Enter */
1196	        editorInsertNewline();
1197	        break;
1198	    case CTRL_C:        /* Ctrl-c */
1199	        /* We ignore ctrl-c, it can't be so simple to lose the changes
1200	         * to the edited file. */
1201	        break;
1202	    case CTRL_Q:        /* Ctrl-q */
1203	        /* Quit if the file was already saved. */
1204	        if (E.dirty && quit_times) {
1205	            editorSetStatusMessage("WARNING!!! File has unsaved changes. "
1206	                "Press Ctrl-Q %d more times to quit.", quit_times);
1207	            quit_times--;
1208	            return;
1209	        }
1210	        exit(0);
1211	        break;
1212	    case CTRL_S:        /* Ctrl-s */
1213	        editorSave();
1214	        break;
1215	    case CTRL_F:
1216	        editorFind(fd);
1217	        break;
1218	    case BACKSPACE:     /* Backspace */
1219	    case CTRL_H:        /* Ctrl-h */
1220	    case DEL_KEY:
1221	        editorDelChar();
1222	        break;
1223	    case PAGE_UP:
1224	    case PAGE_DOWN:
1225	        if (c == PAGE_UP && E.cy != 0)
1226	            E.cy = 0;
1227	        else if (c == PAGE_DOWN && E.cy != E.screenrows-1)
1228	            E.cy = E.screenrows-1;
1229	        {
1230	        int times = E.screenrows;
1231	        while(times--)
1232	            editorMoveCursor(c == PAGE_UP ? ARROW_UP:
1233	                                            ARROW_DOWN);
1234	        }
1235	        break;
1236	
1237	    case ARROW_UP:
1238	    case ARROW_DOWN:
1239	    case ARROW_LEFT:
1240	    case ARROW_RIGHT:
1241	        editorMoveCursor(c);
1242	        break;
1243	    case CTRL_L: /* ctrl+l, clear screen */
1244	        /* Just refresht the line as side effect. */
1245	        break;
1246	    case ESC:
1247	        /* Nothing to do for ESC in this mode. */
1248	        break;
1249	    default:
1250	        editorInsertChar(c);
1251	        break;
1252	    }
1253	
1254	    quit_times = KILO_QUIT_TIMES; /* Reset it to the original value. */
1255	}
1256	
1257	int editorFileWasModified(void) {
1258	    return E.dirty;
1259	}
1260	
1261	void updateWindowSize(void) {
1262	    if (getWindowSize(STDIN_FILENO,STDOUT_FILENO,
1263	                      &E.screenrows,&E.screencols) == -1) {
1264	        perror("Unable to query the screen for size (columns / rows)");
1265	        exit(1);
1266	    }
1267	    E.screenrows -= 2; /* Get room for status bar. */
1268	}
1269	
1270	void handleSigWinCh(int unused __attribute__((unused))) {
1271	    updateWindowSize();
1272	    if (E.cy > E.screenrows) E.cy = E.screenrows - 1;
1273	    if (E.cx > E.screencols) E.cx = E.screencols - 1;
1274	    editorRefreshScreen();
1275	}
1276	
1277	void initEditor(void) {
1278	    E.cx = 0;
1279	    E.cy = 0;
1280	    E.rowoff = 0;
1281	    E.coloff = 0;
1282	    E.numrows = 0;
1283	    E.row = NULL;
1284	    E.dirty = 0;
1285	    E.filename = NULL;
1286	    E.syntax = NULL;
1287	    updateWindowSize();
1288	    signal(SIGWINCH, handleSigWinCh);
1289	}
1290	
1291	int main(int argc, char **argv) {
1292	    if (argc != 2) {
1293	        fprintf(stderr,"Usage: kilo <filename>\n");
1294	        exit(1);
1295	    }
1296	
1297	    initEditor();
1298	    editorSelectSyntaxHighlight(argv[1]);
1299	    editorOpen(argv[1]);
1300	    enableRawMode(STDIN_FILENO);
1301	    editorSetStatusMessage(
1302	        "HELP: Ctrl-S = save | Ctrl-Q = quit | Ctrl-F = find");
1303	    while(1) {
1304	        editorRefreshScreen();
1305	        editorProcessKeypress(STDIN_FILENO);
1306	    }
1307	    return 0;
1308	}
